"}, {"source_file": "2027.xlsx", "source_sheet": "FEBRERO", "source_row": 16, "source_col": 6, "event_date": "2027-02-06", "raw_text": "DIPLOMADO \"ROL DE ENFERMERÃA EN NEONATOLOGÃA Y PEDIATRÃA\" MOD VI CLASE 2 (CLAUSURA) (ASINCRÃ“NICO)  5PM - 7PM", "title": "DIPLOMADO \"ROL DE ENFERMERÃA EN NEONATOLOGÃA Y PEDIATRÃA\" MOD VI CLASE 2 (CLAUSURA) (ASINCRÃ“NICO)", "modality_slug": "asincronico", "event_type_slug": "diplomado", "specialty_slug": "enfermeria", "specialty_name": "Enfermeria", "audience_name": "Profesionales de salud", "start_time": "17:00", "end_time": "19:00", "email": null, "import_code": "IMP-20270206-0982"}, {"source_file": "2027.xlsx", "source_sheet": "FEBRERO", "source_row": 29, "source_col": 6, "event_date": "2027-02-13", "raw_text": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VII CLASE 2 (ASINCRÃ“NICO) 4 PM A 6 PM", "title": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VII CLASE 2 (ASINCRÃ“NICO)", "modality_slug": "asincronico", "event_type_slug": "diplomado", "specialty_slug": "radiologia", "specialty_name": "Radiologia", "audience_name": "Profesionales de salud", "start_time": "16:00", "end_time": "18:00", "email": null, "import_code": "IMP-20270213-0983"}, {"source_file": "2027.xlsx", "source_sheet": "FEBRERO", "source_row": 66, "source_col": 6, "event_date": "2027-02-27", "raw_text": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VIII CLASE 1 (ASINCRÃ“NICO) 4 PM A 6 PM", "title": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VIII CLASE 1 (ASINCRÃ“NICO)", "modality_slug": "asincronico", "event_type_slug": "diplomado", "specialty_slug": "radiologia", "specialty_name": "Radiologia", "audience_name": "Profesionales de salud", "start_time": "16:00", "end_time": "18:00", "email": null, "import_code": "IMP-20270227-0984"}, {"source_file": "2027.xlsx", "source_sheet": "MARZO", "source_row": 32, "source_col": 6, "event_date": "2027-03-13", "raw_text": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VIII CLASE 2 (ASINCRÃ“NICO) 4 PM A 6 PM", "title": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" MOD VIII CLASE 2 (ASINCRÃ“NICO)", "modality_slug": "asincronico", "event_type_slug": "diplomado", "specialty_slug": "radiologia", "specialty_name": "Radiologia", "audience_name": "Profesionales de salud", "start_time": "16:00", "end_time": "18:00", "email": null, "import_code": "IMP-20270313-0985"}, {"source_file": "2027.xlsx", "source_sheet": "MARZO", "source_row": 71, "source_col": 6, "event_date": "2027-03-27", "raw_text": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" TALLER III (PRESENCIAL) 4 PM A 8 PM", "title": "DIPLOMADO \"ECOGRAFÃA GENERAL Y ESPECIALIZADA\" TALLER III", "modality_slug": "presencial", "event_type_slug": "diplomado", "specialty_slug": "radiologia", "specialty_name": "Radiologia", "audience_name": "Profesionales de salud", "start_time": "16:00", "end_time": "20:00", "email": null, "import_code": "IMP-20270327-0986"}]$json$::jsonb) as x(
        import_code text,
        source_file text,
        source_sheet text,
        source_row int,
        source_col int,
        event_date date,
        raw_text text,
        title text,
        modality_slug text,
        event_type_slug text,
        specialty_slug text,
        specialty_name text,
        audience_name text,
        start_time time,
        end_time time,
        email text
    )
), admin_user as (
    select id from users order by id limit 1
), specialty_upsert as (
    insert into specialties (name, slug, is_active, created_at, updated_at)
    select distinct specialty_name, specialty_slug, true, now(), now() from payload
    on conflict (slug) do update set name = excluded.name, is_active = true, updated_at = now()
    returning id, slug
), audience_upsert as (
    insert into audience_segments (name, description, career_area, priority_level, is_active, created_at, updated_at)
    select distinct p.audience_name, 'Importado desde calendario Excel', 'Salud', 3, true, now(), now()
    from payload p
    where not exists (select 1 from audience_segments a where a.name = p.audience_name)
), zoom_upsert as (
    insert into zoom_accounts (name, email, capacity, is_active, created_at, updated_at)
    select distinct 'Importado ' || email, email, 500, true, now(), now() from payload where email is not null
    on conflict (email) do update set is_active = true, updated_at = now()
), event_insert as (
    insert into academic_events (
        code, name, short_name, event_type_id, modality_id, specialty_id, audience_segment_id,
        start_date, end_date, duration_months, total_hours, status, commercial_priority, created_by, created_at, updated_at
    )
    select p.import_code,
           p.title,
           left(p.title, 60),
           et.id,
           m.id,
           s.id,
           a.id,
           p.event_date,
           p.event_date,
           1,
           greatest(1, ceil(extract(epoch from (p.end_time - p.start_time)) / 3600.0))::int,
           'IMPORTADO',
           'MEDIA',
           (select id from admin_user),
           now(),
           now()
    from payload p
    join event_types et on et.slug = p.event_type_slug
    join modalities m on m.slug = p.modality_slug
    join specialties s on s.slug = p.specialty_slug
    join audience_segments a on a.name = p.audience_name
    on conflict (code) do update set
        name = excluded.name,
        short_name = excluded.short_name,
        event_type_id = excluded.event_type_id,
        modality_id = excluded.modality_id,
        specialty_id = excluded.specialty_id,
        audience_segment_id = excluded.audience_segment_id,
        start_date = excluded.start_date,
        end_date = excluded.end_date,
        total_hours = excluded.total_hours,
        status = excluded.status,
        updated_at = now()
    returning id, code
), session_insert as (
    insert into event_sessions (
        academic_event_id, session_number, module_number, session_type, title, date, start_time, end_time,
        duration_minutes, modality_id, zoom_account_id, status, is_holiday, is_exception, created_at, updated_at
    )
    select ae.id,
           1,
           1,
           'IMPORTADO',
           p.title,
           p.event_date,
           p.start_time,
           p.end_time,
           greatest(60, (extract(epoch from (p.end_time - p.start_time)) / 60)::int),
           m.id,
           z.id,
           'IMPORTADA',
           false,
           false,
           now(),
           now()
    from payload p
    join academic_events ae on ae.code = p.import_code
    join modalities m on m.slug = p.modality_slug
    left join zoom_accounts z on z.email = p.email
    where not exists (select 1 from event_sessions es where es.academic_event_id = ae.id and es.session_number = 1)
    returning id, academic_event_id
)
insert into imported_calendar_events (
    import_code, source_file, source_sheet, source_row, source_col, event_date, raw_text, parsed_title,
    modality_slug, event_type_slug, specialty_slug, audience_name, start_time, end_time, email,
    academic_event_id, event_session_id, created_at, updated_at
)
select p.import_code, p.source_file, p.source_sheet, p.source_row, p.source_col, p.event_date, p.raw_text, p.title,
       p.modality_slug, p.event_type_slug, p.specialty_slug, p.audience_name, p.start_time, p.end_time, p.email,
       ae.id, es.id, now(), now()
from payload p
join academic_events ae on ae.code = p.import_code
left join event_sessions es on es.academic_event_id = ae.id and es.session_number = 1
on conflict (import_code) do update set
    raw_text = excluded.raw_text,
    parsed_title = excluded.parsed_title,
    academic_event_id = excluded.academic_event_id,
    event_session_id = excluded.event_session_id,
    updated_at = now();

commit;


